// Weekly fortune content pillar (gentle + render)
// IMPORTANT: Reference time is *Taipei local time* (Asia/Taipei).
// We send both a Taipei-local string and an ISO timestamp for debugging.

const tz = 'Asia/Taipei';
const now = new Date();

// Compute next Monday 12:00 in Taipei local semantics (week base).
const ref = new Date(now);
const day = ref.getDay(); // 0 Sun .. 6 Sat
const diffToMon = (8 - day) % 7; // days until next Mon (0 if Mon)
ref.setDate(ref.getDate() + diffToMon);
ref.setHours(12, 0, 0, 0);

// Format as Taipei-local string: YYYY-MM-DD HH:mm:ss
const parts = new Intl.DateTimeFormat('sv-SE', {
  timeZone: tz,
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit', second: '2-digit',
  hour12: false
}).formatToParts(ref).reduce((acc,p)=>{acc[p.type]=p.value;return acc;},{});
const referenceLocalTime = `${parts.year}-${parts.month}-${parts.day} ${parts.hour}:${parts.minute}:${parts.second}`;

return [{
  json: {
    kind: 'weekly_fortune',
    referenceLocalTime,
    timezone: tz,
    referenceIsoUtc: ref.toISOString(),
    tone: 'gentle_render',
    cta: 'line_free_divination',
    channels: ['ig', 'threads', 'short_video'],
    placeholder: true,
    note: 'Template workflow: Creator should compute BaZi using referenceLocalTime+timezone; replace placeholder once API is ready.'
  }
}];
